export const WIDGET_HTML: string = "<!doctype html>\n<html lang=\"en\">\n<head>\n<meta charset=\"utf-8\" />\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n<title>Bouncr</title>\n<link rel=\"icon\" type=\"image/svg+xml\" href=\"data:image/svg+xml;base64,\" />\n<style>\n  :root {\n    --accent: #7C3AED;     /* electric violet — the persona color */\n    --mint: #34D399;       /* deal mint — used ONLY on the deal-reached screen */\n    --bg: #0B0B12;         /* noir — near-black with a violet tint */\n    --panel: #14141c;\n    --bubble-bot: #1d1d27;\n    --bubble-user: var(--accent);\n    --text: #ECECF1;\n    --muted: #8a8a99;\n    --line: #26262f;\n  }\n  * { box-sizing: border-box; }\n  html, body { margin: 0; height: 100%; }\n  body {\n    background: var(--bg); color: var(--text);\n    font: 15px/1.45 ui-sans-serif, system-ui, -apple-system, \"Segoe UI\", Roboto, sans-serif;\n    display: flex; flex-direction: column; height: 100vh;\n  }\n  header {\n    display: flex; align-items: center; gap: 10px;\n    padding: 12px 16px; border-bottom: 1px solid var(--line); background: var(--panel);\n  }\n  .avatar {\n    width: 34px; height: 34px; border-radius: 50%;\n    background: var(--accent); display: grid; place-items: center;\n    font-weight: 700; font-size: 16px; color: #fff; flex: 0 0 auto;\n  }\n  .who { display: flex; flex-direction: column; line-height: 1.2; }\n  .who b { font-size: 14px; }\n  .who span { font-size: 12px; color: var(--muted); }\n  .timer {\n    margin-left: auto; font-size: 12px; color: var(--muted);\n    font-variant-numeric: tabular-nums;\n  }\n  .timer.urgent { color: #f59e0b; font-weight: 600; }\n  #log { flex: 1; overflow-y: auto; padding: 16px; display: flex; flex-direction: column; gap: 10px; }\n  .msg { max-width: 80%; padding: 9px 13px; border-radius: 16px; white-space: pre-wrap; word-wrap: break-word; }\n  .msg.bot { background: var(--bubble-bot); border-bottom-left-radius: 5px; align-self: flex-start; }\n  .msg.user { background: var(--bubble-user); color: #fff; border-bottom-right-radius: 5px; align-self: flex-end; }\n  .typing { align-self: flex-start; color: var(--muted); font-size: 13px; padding: 4px 13px; }\n  .dot { display: inline-block; animation: blink 1.2s infinite both; }\n  .dot:nth-child(2) { animation-delay: .2s; } .dot:nth-child(3) { animation-delay: .4s; }\n  @keyframes blink { 0%,80%,100% { opacity: .2 } 40% { opacity: 1 } }\n  #chips { display: flex; flex-wrap: wrap; gap: 8px; padding: 0 16px 8px; }\n  .chip {\n    border: 1px solid var(--accent); color: var(--text); background: transparent;\n    border-radius: 999px; padding: 7px 14px; font-size: 13px; cursor: pointer;\n  }\n  .chip.primary { background: var(--accent); color: #fff; border-color: var(--accent); font-weight: 600; }\n  .chip:active { transform: translateY(1px); }\n  form { display: flex; gap: 8px; padding: 12px 16px; border-top: 1px solid var(--line); background: var(--panel); }\n  textarea {\n    flex: 1; resize: none; background: #0c0c10; color: var(--text);\n    border: 1px solid var(--line); border-radius: 12px; padding: 10px 12px; font: inherit; height: 42px;\n  }\n  button.send { background: var(--accent); color: #fff; border: 0; border-radius: 12px; padding: 0 18px; cursor: pointer; font-weight: 600; }\n  button:disabled { opacity: .5; cursor: default; }\n  /* deal / walk screens */\n  .screen {\n    position: absolute; inset: 0; background: var(--bg);\n    display: none; flex-direction: column; align-items: center; justify-content: center;\n    text-align: center; padding: 28px; gap: 14px;\n  }\n  .screen.show { display: flex; }\n  .deal-price { font-size: 52px; font-weight: 800; letter-spacing: -1px; }\n  .deal-price small { font-size: 18px; color: var(--muted); font-weight: 500; }\n  .deal-line { color: var(--text); max-width: 22em; font-size: 16px; }\n  .deal-cta {\n    background: var(--accent); color: #fff; border: 0; border-radius: 12px;\n    padding: 13px 26px; font-size: 16px; font-weight: 700; cursor: pointer; text-decoration: none;\n  }\n  /* DEAL MINT — the win. Mint appears nowhere else in the product but here, the\n     moment a deal is reached; the scarcity is what makes the win feel earned. */\n  #deal-screen { background: radial-gradient(130% 90% at 50% -10%, rgba(52,211,153,.16), var(--bg) 58%); }\n  #deal-screen .deal-price { color: var(--mint); text-shadow: 0 0 46px rgba(52,211,153,.5); animation: dealpop .5s cubic-bezier(.2,.9,.3,1.2); }\n  #deal-screen .deal-cta { background: var(--mint); color: #04241a; }\n  @keyframes dealpop { 0% { transform: scale(.82); opacity: 0 } 60% { transform: scale(1.06) } 100% { transform: scale(1); opacity: 1 } }\n  #deal-screen .deal-emblem { color: var(--mint); width: 54px; height: 54px; display: block; filter: drop-shadow(0 0 22px rgba(52,211,153,.5)); animation: dealpop .5s cubic-bezier(.2,.9,.3,1.2); }\n  #deal-screen .deal-emblem svg { width: 100%; height: 100%; display: block; }\n  .mark { position: absolute; bottom: 14px; font-size: 11px; color: var(--muted); letter-spacing: .3px; }\n  .mark b { color: var(--accent); }\n  a.fallback { color: var(--accent); }\n</style>\n</head>\n<body>\n  <header>\n    <div class=\"avatar\" id=\"avatar\">B</div>\n    <div class=\"who\"><b id=\"who-name\">Bouncr</b><span id=\"who-product\">negotiate your price</span></div>\n    <div class=\"timer\" id=\"timer\"></div>\n  </header>\n\n  <div id=\"log\" role=\"log\" aria-live=\"polite\"></div>\n  <div id=\"chips\"></div>\n\n  <form id=\"form\" autocomplete=\"off\">\n    <textarea id=\"input\" placeholder=\"Make your case…\" aria-label=\"Your message\" rows=\"1\"></textarea>\n    <button class=\"send\" id=\"send\" type=\"submit\">Send</button>\n  </form>\n\n  <div class=\"screen\" id=\"deal-screen\">\n    <span class=\"deal-emblem\"><svg viewBox=\"0 0 100 100\" aria-hidden=\"true\"><circle cx=\"50\" cy=\"30\" r=\"10\" fill=\"currentColor\"/><path d=\"M27 62 L73 51\" stroke=\"currentColor\" stroke-width=\"11\" stroke-linecap=\"round\" fill=\"none\"/><path d=\"M27 51 L73 62\" stroke=\"currentColor\" stroke-width=\"11\" stroke-linecap=\"round\" fill=\"none\"/></svg></span>\n    <div class=\"deal-price\" id=\"deal-price\"></div>\n    <div class=\"deal-line\" id=\"deal-line\"></div>\n    <a class=\"deal-cta\" id=\"deal-cta\" target=\"_top\">Continue to checkout →</a>\n    <div class=\"mark\">negotiated via <b>Bouncr</b></div>\n  </div>\n\n  <div class=\"screen\" id=\"walk-screen\">\n    <div class=\"deal-price\">🚪</div>\n    <div class=\"deal-line\" id=\"walk-line\">That's a wrap. No deal this time.</div>\n    <a class=\"deal-cta\" id=\"walk-cta\" target=\"_top\">See standard pricing</a>\n    <div class=\"mark\">negotiated via <b>Bouncr</b></div>\n  </div>\n\n  <noscript>\n    <div style=\"padding:24px\">Negotiation needs JavaScript. <a class=\"fallback\" id=\"ns-fallback\" href=\"#\">See standard pricing.</a></div>\n  </noscript>\n\n<script>\n(() => {\n  const q = new URLSearchParams(location.search);\n  const base = (q.get(\"base\") || location.origin).replace(/\\/$/, \"\");\n  const planId = q.get(\"plan\") || \"plan_demo\";\n  const userRef = q.get(\"user\") || (\"anon_\" + Math.random().toString(36).slice(2, 10));\n  const accent = q.get(\"accent\");\n  const fallbackUrl = q.get(\"fallback\") || \"#\";\n  if (accent) document.documentElement.style.setProperty(\"--accent\", \"#\" + accent.replace(/^#/, \"\"));\n\n  const $ = (id) => document.getElementById(id);\n  const log = $(\"log\"), chips = $(\"chips\"), input = $(\"input\"), form = $(\"form\"), sendBtn = $(\"send\");\n  $(\"walk-cta\").href = fallbackUrl; $(\"deal-cta\").href = \"#\";\n\n  let sessionId = q.get(\"session\") || null;\n  let token = q.get(\"token\") || null;\n  let expiresAt = 0;\n  let currentAsk = 0;\n  let busy = false;\n\n  const post = (path, body, headers) =>\n    fetch(base + path, {\n      method: \"POST\",\n      headers: Object.assign({ \"content-type\": \"application/json\" }, headers || {}),\n      body: body === undefined ? undefined : JSON.stringify(body),\n    });\n\n  function notifyParent(type, payload) {\n    try { window.parent.postMessage({ source: \"bouncr\", type, payload }, \"*\"); } catch (_) {}\n  }\n\n  function addMsg(role, text) {\n    const el = document.createElement(\"div\");\n    el.className = \"msg \" + (role === \"user\" ? \"user\" : \"bot\");\n    el.textContent = text;\n    log.appendChild(el);\n    log.scrollTop = log.scrollHeight;\n    return el;\n  }\n\n  function typewriter(el, text) {\n    el.textContent = \"\";\n    let i = 0;\n    const step = () => {\n      el.textContent = text.slice(0, (i += 2));\n      log.scrollTop = log.scrollHeight;\n      if (i < text.length) setTimeout(step, 12);\n    };\n    step();\n  }\n\n  function showTyping() {\n    const el = document.createElement(\"div\");\n    el.className = \"typing\"; el.id = \"typing\";\n    el.innerHTML = '<span class=\"dot\">●</span><span class=\"dot\">●</span><span class=\"dot\">●</span>';\n    log.appendChild(el); log.scrollTop = log.scrollHeight;\n  }\n  function hideTyping() { const t = $(\"typing\"); if (t) t.remove(); }\n\n  function renderChips(state, action) {\n    chips.innerHTML = \"\";\n    if (!state || state.status !== \"open\") return;\n    if (action && action.type === \"counter\") {\n      const take = document.createElement(\"button\");\n      take.className = \"chip primary\";\n      take.textContent = \"Take $\" + state.current_ask + \"/mo\";\n      take.onclick = acceptCurrent;\n      const keep = document.createElement(\"button\");\n      keep.className = \"chip\";\n      keep.textContent = \"Keep haggling\";\n      keep.onclick = () => input.focus();\n      chips.append(take, keep);\n    }\n  }\n\n  function setTimer() {\n    const t = $(\"timer\");\n    if (!expiresAt) { t.textContent = \"\"; return; }\n    const tick = () => {\n      const ms = expiresAt - Date.now();\n      // A multi-hour countdown is just noise — keep the header clean and only\n      // surface the clock in the final hour, where it's a real urgency cue.\n      if (ms <= 0) { t.textContent = \"expired\"; return; }\n      if (ms > 3600000) { t.textContent = \"\"; return; }\n      const m = Math.floor(ms / 60000);\n      t.textContent = `${m}m left`;\n    };\n    tick(); setInterval(tick, 30000);\n  }\n\n  function endInput() { input.disabled = true; sendBtn.disabled = true; chips.innerHTML = \"\"; }\n\n  function showDeal(price, line, checkoutUrl, dealId) {\n    endInput();\n    $(\"deal-price\").innerHTML = \"$\" + price + \"<small>/mo</small>\";\n    $(\"deal-line\").textContent = line || \"You earned it.\";\n    const cta = $(\"deal-cta\");\n    if (checkoutUrl) cta.href = checkoutUrl; else cta.style.display = \"none\";\n    $(\"deal-screen\").classList.add(\"show\");\n    notifyParent(\"deal\", { price, checkoutUrl, dealId });\n  }\n\n  function showWalk(line) {\n    endInput();\n    if (line) $(\"walk-line\").textContent = line;\n    $(\"walk-screen\").classList.add(\"show\");\n    notifyParent(\"walkaway\", {});\n  }\n\n  function handleReply(data) {\n    const el = addMsg(\"bot\", \"\");\n    typewriter(el, data.reply);\n    if (data.state) { currentAsk = data.state.current_ask; }\n    if (data.is_final) { $(\"timer\").classList.add(\"urgent\"); }\n\n    if (data.action && data.action.type === \"accept\") {\n      setTimeout(() => showDeal(data.action.amount, data.reply, data.checkout_url, data.deal_id), 600);\n    } else if (data.action && data.action.type === \"walk\") {\n      setTimeout(() => showWalk(data.reply), 600);\n    } else {\n      renderChips(data.state, data.action);\n    }\n  }\n\n  async function streamMessage(text) {\n    showTyping();\n    const res = await post(`/v1/sessions/${sessionId}/messages/stream`, { message: text }, { \"x-session-token\": token });\n    if (!res.ok || !res.body) {\n      hideTyping();\n      addMsg(\"bot\", \"Hmm, something glitched. Try again.\");\n      return;\n    }\n    const reader = res.body.getReader();\n    const dec = new TextDecoder();\n    let buf = \"\";\n    let firstReply = true;\n    while (true) {\n      const { value, done } = await reader.read();\n      if (done) break;\n      buf += dec.decode(value, { stream: true });\n      let idx;\n      while ((idx = buf.indexOf(\"\\n\\n\")) >= 0) {\n        const block = buf.slice(0, idx); buf = buf.slice(idx + 2);\n        let ev = \"message\", data = \"\";\n        for (const line of block.split(\"\\n\")) {\n          if (line.startsWith(\"event:\")) ev = line.slice(6).trim();\n          else if (line.startsWith(\"data:\")) data += line.slice(5).trim();\n        }\n        if (ev === \"reply\" && firstReply) {\n          firstReply = false; hideTyping();\n          handleReply(JSON.parse(data));\n        } else if (ev === \"error\") {\n          hideTyping();\n          addMsg(\"bot\", \"Couldn't process that — \" + (JSON.parse(data).error || \"error\"));\n        }\n      }\n    }\n  }\n\n  async function acceptCurrent() {\n    if (busy) return; busy = true; chips.innerHTML = \"\";\n    try {\n      const res = await post(`/v1/sessions/${sessionId}/accept`, undefined, { \"x-session-token\": token });\n      const d = await res.json();\n      if (res.ok) showDeal(d.price, \"Smart. Locked in.\", d.checkout_url, d.deal_id);\n      else addMsg(\"bot\", \"Can't close that right now.\");\n    } finally { busy = false; }\n  }\n\n  form.addEventListener(\"submit\", async (e) => {\n    e.preventDefault();\n    const text = input.value.trim();\n    if (!text || busy) return;\n    busy = true; input.value = \"\"; chips.innerHTML = \"\";\n    addMsg(\"user\", text);\n    try { await streamMessage(text); } finally { busy = false; input.focus(); }\n  });\n  input.addEventListener(\"keydown\", (e) => {\n    if (e.key === \"Enter\" && !e.shiftKey) { e.preventDefault(); form.requestSubmit(); }\n  });\n\n  async function init() {\n    try {\n      if (sessionId && token) {\n        // Server-mediated: session already created, just resume.\n        const v = await fetch(`${base}/v1/sessions/${sessionId}`, { headers: { \"x-session-token\": token } });\n        if (v.ok) { const s = await v.json(); expiresAt = s.expires_at; currentAsk = s.current_ask; }\n      } else {\n        const res = await post(\"/v1/sessions\", { plan_id: planId, end_user_ref: userRef });\n        if (!res.ok) throw new Error(\"create failed \" + res.status);\n        const s = await res.json();\n        sessionId = s.session_id; token = s.session_token; expiresAt = s.expires_at;\n        addMsg(\"bot\", s.opener_message);\n      }\n      setTimer();\n      input.focus();\n    } catch (err) {\n      addMsg(\"bot\", \"Couldn't start the negotiation. \" + (fallbackUrl !== \"#\" ? \"See standard pricing.\" : \"\"));\n      console.error(err);\n    }\n  }\n  init();\n})();\n</script>\n</body>\n</html>\n";
export const EMBED_JS: string = "/*\n * Bouncr embed loader (Spec §10). Script tag → iframe, so it works on any stack.\n *\n * Auto-mount from data attributes:\n *   <script src=\"https://bouncr.tech/embed.js\"\n *           data-plan=\"pro_monthly\" data-user=\"user_123\"\n *           data-mount=\"#bouncr\" data-accent=\"7C3AED\"\n *           data-fallback=\"https://yourapp.com/pricing\"></script>\n *\n * Or programmatically:\n *   <script src=\"https://bouncr.tech/embed.js\"></script>\n *   <script>\n *     Bouncr.mount({\n *       el: \"#bouncr\", planId: \"pro_monthly\", userRef: user.id,\n *       theme: { accent: \"7C3AED\" },\n *       onDeal: (d) => { window.location = d.checkoutUrl },   // default if omitted\n *       onWalkaway: () => showStandardPricing(),\n *     });\n *   </script>\n */\n(function () {\n  var current = document.currentScript;\n  var ORIGIN = current ? new URL(current.src).origin : window.location.origin;\n\n  function buildUrl(opts) {\n    var p = new URLSearchParams();\n    p.set(\"base\", ORIGIN);\n    if (opts.planId) p.set(\"plan\", opts.planId);\n    if (opts.userRef) p.set(\"user\", opts.userRef);\n    if (opts.theme && opts.theme.accent) p.set(\"accent\", String(opts.theme.accent).replace(/^#/, \"\"));\n    if (opts.theme && opts.theme.mode) p.set(\"mode\", opts.theme.mode);\n    if (opts.fallbackUrl) p.set(\"fallback\", opts.fallbackUrl);\n    if (opts.session) p.set(\"session\", opts.session);\n    if (opts.token) p.set(\"token\", opts.token);\n    return ORIGIN + \"/widget?\" + p.toString();\n  }\n\n  function resolveEl(el) {\n    if (!el) {\n      var d = document.createElement(\"div\");\n      d.style.cssText =\n        \"position:fixed;right:20px;bottom:20px;width:380px;height:560px;max-width:92vw;max-height:80vh;z-index:2147483000;box-shadow:0 20px 60px rgba(0,0,0,.45);border-radius:16px;overflow:hidden\";\n      document.body.appendChild(d);\n      return d;\n    }\n    return typeof el === \"string\" ? document.querySelector(el) : el;\n  }\n\n  function mount(opts) {\n    opts = opts || {};\n    var host = resolveEl(opts.el);\n    if (!host) { console.error(\"[bouncr] mount target not found:\", opts.el); return; }\n\n    var iframe = document.createElement(\"iframe\");\n    iframe.src = buildUrl(opts);\n    iframe.title = \"Bouncr negotiation\";\n    iframe.allow = \"clipboard-write\";\n    iframe.style.cssText = \"width:100%;height:100%;border:0;display:block;background:#0B0B12\";\n    iframe.setAttribute(\"loading\", \"lazy\");\n    host.appendChild(iframe);\n\n    var onDeal = typeof opts.onDeal === \"function\" ? opts.onDeal : function (d) {\n      if (d && d.checkoutUrl) window.location.href = d.checkoutUrl;\n    };\n    var onWalkaway = typeof opts.onWalkaway === \"function\" ? opts.onWalkaway : function () {};\n\n    function handler(e) {\n      if (e.origin !== ORIGIN) return; // only trust the Bouncr origin\n      var m = e.data;\n      if (!m || m.source !== \"bouncr\") return;\n      if (m.type === \"deal\") onDeal(m.payload || {});\n      else if (m.type === \"walkaway\") onWalkaway(m.payload || {});\n    }\n    window.addEventListener(\"message\", handler);\n\n    return {\n      iframe: iframe,\n      destroy: function () { window.removeEventListener(\"message\", handler); iframe.remove(); },\n    };\n  }\n\n  window.Bouncr = { mount: mount };\n\n  // Auto-mount if the script tag carries data-plan.\n  if (current && current.dataset && current.dataset.plan) {\n    var d = current.dataset;\n    mount({\n      el: d.mount || null,\n      planId: d.plan,\n      userRef: d.user,\n      theme: { accent: d.accent, mode: d.mode },\n      fallbackUrl: d.fallback,\n    });\n  }\n})();\n";
export const DEMO_HTML: string = "<!doctype html>\n<html lang=\"en\">\n<head>\n<meta charset=\"utf-8\" />\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n<title>Bouncr — playground</title>\n<link rel=\"icon\" type=\"image/svg+xml\" href=\"data:image/svg+xml;base64,\" />\n<style>\n  body { margin: 0; font: 16px/1.5 ui-sans-serif, system-ui, sans-serif; color: #ECECF1; background: #0B0B12; }\n  .wrap { max-width: 720px; margin: 0 auto; padding: 56px 24px; }\n  h1 { font-size: 34px; letter-spacing: -0.5px; margin: 0 0 8px; }\n  p.lede { color: #8b8b99; font-size: 18px; margin: 0 0 28px; }\n  .card { border: 1px solid #23232e; border-radius: 16px; padding: 22px; background: #15151f; }\n  .price { font-size: 40px; font-weight: 800; margin: 4px 0 2px; }\n  .price s { color: #5a5a6a; font-weight: 400; font-size: 22px; }\n  button.cta { margin-top: 14px; background: #7C3AED; color: #fff; border: 0; border-radius: 10px; padding: 12px 22px; font-size: 16px; font-weight: 700; cursor: pointer; }\n  /* deal banner = the mint moment; walk banner gets a neutral rose (set in JS) */\n  #banner { display: none; margin: 18px 0 0; padding: 14px 16px; border-radius: 12px; background: rgba(52,211,153,.1); color: #34D399; border: 1px solid rgba(52,211,153,.35); }\n  #banner code { background: rgba(52,211,153,.14); color: inherit; }\n  #panel { margin-top: 28px; height: 560px; max-height: 70vh; border: 1px solid #23232e; border-radius: 16px; overflow: hidden; }\n  code { background: #1d1d27; color: #c4b5fd; padding: 2px 6px; border-radius: 5px; font-size: 14px; }\n</style>\n</head>\n<body>\n  <div class=\"wrap\">\n    <h1>Don't pay the sticker price.</h1>\n    <p class=\"lede\">This is Obius Pro. The list is $30/mo — but Vinny on the door decides what <em>you</em> pay. Make your case.</p>\n\n    <div class=\"card\">\n      <div>Obius Pro</div>\n      <div class=\"price\"><s>$30</s> negotiable</div>\n      <button class=\"cta\" id=\"open\">Talk to the bouncer</button>\n      <div id=\"banner\"></div>\n    </div>\n\n    <div id=\"panel\"></div>\n\n    <p style=\"margin-top:28px;color:#8b8b99;font-size:14px\">\n      Embed this anywhere with one tag: <code>&lt;script src=\"/embed.js\" data-plan=\"pro_monthly\"&gt;&lt;/script&gt;</code>\n    </p>\n  </div>\n\n  <script src=\"/embed.js\"></script>\n  <script>\n    var mounted = null;\n    document.getElementById(\"open\").addEventListener(\"click\", function () {\n      if (mounted) return;\n      mounted = window.Bouncr.mount({\n        el: \"#panel\",\n        planId: \"pro_monthly\",\n        userRef: \"playground_\" + Math.random().toString(36).slice(2, 8),\n        theme: { accent: \"7C3AED\" },\n        fallbackUrl: \"#\",\n        // Demo: show the deal instead of navigating to the (sandbox) checkout URL.\n        onDeal: function (d) {\n          var b = document.getElementById(\"banner\");\n          b.style.display = \"block\";\n          b.innerHTML = \"🎉 You negotiated <b>$\" + d.price + \"/mo</b> — checkout: <code>\" + (d.checkoutUrl || \"n/a\") + \"</code>\";\n        },\n        onWalkaway: function () {\n          var b = document.getElementById(\"banner\");\n          b.style.display = \"block\";\n          b.style.background = \"rgba(248,113,113,.1)\"; b.style.color = \"#f87171\"; b.style.borderColor = \"rgba(248,113,113,.35)\";\n          b.textContent = \"Vinny walked. Standard pricing it is.\";\n        },\n      });\n    });\n  </script>\n</body>\n</html>\n";
export const DASHBOARD_HTML: string = "<!doctype html>\n<html lang=\"en\">\n<head>\n<meta charset=\"utf-8\" />\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n<title>Bouncr — merchant dashboard</title>\n<link rel=\"icon\" type=\"image/svg+xml\" href=\"data:image/svg+xml;base64,\" />\n<style>\n  :root { --accent: #7C3AED; --mint: #34D399; --ok: #34D399; --warn: #d9941f; --err: #f87171; --line: #23232e; --muted: #8b8b99; }\n  * { box-sizing: border-box; }\n  body { margin: 0; font: 15px/1.5 ui-sans-serif, system-ui, sans-serif; color: #ECECF1; background: #0B0B12; }\n  .wrap { max-width: 1000px; margin: 0 auto; padding: 28px 22px 64px; }\n  h1 { font-size: 24px; margin: 0 0 4px; letter-spacing: -0.4px; }\n  .sub { color: var(--muted); margin: 0 0 20px; }\n  .bar { display: flex; gap: 8px; flex-wrap: wrap; align-items: center; margin-bottom: 22px; }\n  input, select { border: 1px solid var(--line); border-radius: 8px; padding: 8px 10px; font: inherit; background: #14141c; color: var(--text); cursor: pointer; }\n  select { max-width: 240px; }\n  .erow { display: flex; gap: 12px; flex-wrap: wrap; margin-bottom: 6px; }\n  .erow > div { flex: 1; min-width: 130px; }\n  #edit-form label { display: block; font-size: 11px; color: var(--muted); margin: 8px 0 4px; }\n  #edit-form input, #edit-form select { width: 100%; max-width: none; cursor: text; }\n  #edit-form select { cursor: pointer; }\n  .keybox { background: #0d0d13; border: 1px solid rgba(124,58,237,.4); border-radius: 11px; padding: 14px; font-family: ui-monospace, Menlo, monospace; font-size: 13px; word-break: break-all; position: relative; }\n  .keybox .copy { position: absolute; top: 8px; right: 8px; padding: 5px 10px; font-size: 12px; }\n  .warn { font-size: 12.5px; color: var(--accent2); margin-top: 8px; }\n  input::placeholder { color: #5a5a6a; }\n  button { background: var(--accent); color: #fff; border: 0; border-radius: 8px; padding: 8px 14px; font-weight: 600; cursor: pointer; }\n  button.ghost { background: transparent; color: var(--accent); border: 1px solid var(--accent); }\n  .grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(150px, 1fr)); gap: 12px; margin-bottom: 22px; }\n  .card { background: #15151f; border: 1px solid var(--line); border-radius: 14px; padding: 16px; }\n  .card h3 { margin: 0 0 8px; font-size: 12px; text-transform: uppercase; letter-spacing: .5px; color: var(--muted); font-weight: 700; }\n  .big { font-size: 30px; font-weight: 800; letter-spacing: -0.5px; }\n  .panel { background: #15151f; border: 1px solid var(--line); border-radius: 14px; padding: 18px; margin-bottom: 18px; }\n  .panel h2 { margin: 0 0 12px; font-size: 16px; }\n  .badge { display: inline-block; padding: 3px 10px; border-radius: 999px; font-size: 12px; font-weight: 700; }\n  .badge.ok { background: rgba(52,211,153,.12); color: var(--ok); } .badge.no { background: rgba(248,113,113,.12); color: var(--err); }\n  table { width: 100%; border-collapse: collapse; font-size: 14px; }\n  th, td { text-align: left; padding: 7px 8px; border-bottom: 1px solid #1d1d27; }\n  th { color: var(--muted); font-weight: 600; font-size: 12px; }\n  tr.session { cursor: pointer; } tr.session:hover { background: #1a1a22; }\n  .pill { font-size: 11px; padding: 2px 7px; border-radius: 999px; background: #1d1d27; }\n  .pill.settled { background: rgba(52,211,153,.12); color: var(--ok); } .pill.walked { background: rgba(248,113,113,.12); color: var(--err); }\n  .pill.accepted { background: rgba(124,58,237,.14); color: #a78bfa; }\n  .tactics div { display: flex; align-items: center; gap: 8px; margin: 4px 0; }\n  .tactics .tb { height: 10px; background: var(--accent); border-radius: 4px; }\n  #drawer { position: fixed; top: 0; right: 0; width: 420px; max-width: 92vw; height: 100vh; background: #14141c; border-left: 1px solid var(--line); box-shadow: -10px 0 30px rgba(0,0,0,.5); transform: translateX(100%); transition: transform .2s; overflow-y: auto; padding: 18px; }\n  #drawer.open { transform: none; }\n  .msg { padding: 8px 11px; border-radius: 12px; margin: 6px 0; max-width: 85%; white-space: pre-wrap; }\n  .msg.user { background: var(--accent); color: #fff; margin-left: auto; } .msg.bot { background: #1d1d27; }\n  .meta { font-size: 11px; color: var(--muted); margin: 1px 4px 8px; }\n  canvas { width: 100%; max-width: 100%; }\n  .err { color: var(--err); }\n  .lint { font-size: 13px; } .lint .e { color: var(--err); } .lint .w { color: var(--warn); }\n</style>\n</head>\n<body>\n<div class=\"wrap\">\n  <h1>Bouncr — WTP dashboard</h1>\n  <p class=\"sub\">Your true demand curve, from your own negotiations.</p>\n\n  <form class=\"bar\" id=\"login\" autocomplete=\"off\">\n    <input id=\"key\" type=\"password\" autocomplete=\"current-password\" placeholder=\"merchant API key (bk_…)\" size=\"40\" />\n    <button id=\"login-btn\" type=\"submit\">Log in</button>\n    <span class=\"meta\">New here? <a href=\"/signup\" style=\"color:var(--accent)\">Create an account →</a></span>\n    <span id=\"login-status\" class=\"meta\"></span>\n  </form>\n\n  <div class=\"bar\" id=\"authed\" style=\"display:none\">\n    <input id=\"base\" placeholder=\"API base\" size=\"22\" />\n    <select id=\"plan\" title=\"Your plans\"></select>\n    <button id=\"refresh\">Refresh</button>\n    <span class=\"meta\">signed in as <b id=\"who\" style=\"color:var(--text)\"></b></span>\n    <button class=\"ghost\" id=\"logout\">Log out</button>\n    <span id=\"status\"></span>\n    <span class=\"meta\" id=\"no-plans\" style=\"display:none\">No plans yet — <a href=\"/signup\" style=\"color:var(--accent)\">create one →</a></span>\n  </div>\n\n  <div class=\"panel\" id=\"connect-panel\">\n    <h2>Settlement</h2>\n    <div>Stripe Connect: <span id=\"connect-badge\" class=\"badge no\">checking…</span>\n      <button class=\"ghost\" id=\"connect-btn\" style=\"margin-left:10px\">Connect Stripe</button></div>\n    <div style=\"margin-top:10px\">Bouncr take-rate: <b id=\"take-rate\" style=\"color:var(--accent)\">—</b>\n      <span class=\"meta\" id=\"take-note\"></span></div>\n    <div class=\"lint\" id=\"lint\" style=\"margin-top:10px\"></div>\n  </div>\n\n  <details class=\"panel\" id=\"account-panel\">\n    <summary style=\"cursor:pointer; font-weight:600; font-size:15px\">Account &amp; API key</summary>\n    <div style=\"margin-top:12px\">\n      <p class=\"meta\" style=\"margin:0 0 12px\">Your API key is your dashboard login. Rotate it if it may be exposed — the old key stops working immediately. Your current session stays signed in.</p>\n      <button class=\"ghost\" id=\"rotate-btn\">Rotate API key</button>\n      <div class=\"keybox\" id=\"newkey-box\" style=\"display:none; margin-top:14px\"><button class=\"ghost copy\" id=\"copy-newkey\" type=\"button\">Copy</button><span id=\"newkey-val\"></span></div>\n      <div class=\"warn\" id=\"rotate-warn\" style=\"display:none\">⚠ Save this now — it's shown once, and your old key no longer works.</div>\n    </div>\n  </details>\n\n  <details class=\"panel\" id=\"edit-panel\">\n    <summary style=\"cursor:pointer; font-weight:600; font-size:15px\">Edit this plan</summary>\n    <form id=\"edit-form\" style=\"margin-top:14px\">\n      <div class=\"erow\">\n        <div><label>Product name</label><input id=\"e-product\" /></div>\n        <div><label>Bouncer name</label><input id=\"e-persona\" /></div>\n        <div><label>Personality</label>\n          <select id=\"e-style\"><option value=\"sassy\">Sassy</option><option value=\"playful\">Playful</option><option value=\"deadpan\">Deadpan</option><option value=\"professional\">Professional</option></select>\n        </div>\n      </div>\n      <div class=\"erow\">\n        <div><label>List $/mo</label><input id=\"e-list\" type=\"number\" min=\"1\" step=\"0.01\" /></div>\n        <div><label>Floor (cost) $/mo</label><input id=\"e-floor\" type=\"number\" min=\"1\" step=\"0.01\" /></div>\n        <div><label>Target $/mo</label><input id=\"e-target\" type=\"number\" min=\"1\" step=\"0.01\" /></div>\n        <div><label>Take-rate % <span style=\"opacity:.6\">(blank = default)</span></label><input id=\"e-fee\" type=\"number\" min=\"0\" max=\"100\" step=\"0.1\" /></div>\n      </div>\n      <div class=\"lint err\" id=\"edit-err\" style=\"margin-top:8px\"></div>\n      <div style=\"display:flex; gap:10px; align-items:center\">\n        <button type=\"submit\" id=\"edit-save\">Save changes</button>\n        <button type=\"button\" class=\"ghost\" id=\"toggle-active\">Deactivate plan</button>\n        <span class=\"meta\" id=\"edit-status\"></span>\n      </div>\n    </form>\n  </details>\n\n  <div class=\"grid\" id=\"funnel\"></div>\n\n  <div class=\"panel\">\n    <h2>Offer distribution</h2>\n    <canvas id=\"hist\" height=\"220\"></canvas>\n    <div class=\"meta\" id=\"hist-legend\"></div>\n  </div>\n\n  <div class=\"grid\" id=\"closing\"></div>\n\n  <div class=\"panel\">\n    <h2>Tactics used</h2>\n    <div class=\"tactics\" id=\"tactics\"></div>\n  </div>\n\n  <div class=\"panel\">\n    <h2>Recent negotiations</h2>\n    <table><thead><tr><th>User</th><th>Status</th><th>Round</th><th>Ask</th></tr></thead>\n      <tbody id=\"sessions\"></tbody></table>\n  </div>\n</div>\n\n<div id=\"drawer\"><button class=\"ghost\" onclick=\"document.getElementById('drawer').classList.remove('open')\">Close</button>\n  <h2 id=\"drawer-title\" style=\"margin-top:12px\"></h2><div id=\"transcript\"></div></div>\n\n<script>\n(() => {\n  const $ = (id) => document.getElementById(id);\n  $(\"base\").value = location.origin;\n  const TKEY = \"bouncr_dash_token\";\n  let token = localStorage.getItem(TKEY) || null;\n  let MERCHANT = null; // id of the signed-in merchant (from the token)\n  let PLANS = [];      // the merchant's plans (for the dropdown + edit form)\n  [\"base\",\"plan\"].forEach((id) => { const v = localStorage.getItem(\"bouncr_dash_\" + id); if (v) $(id).value = v; });\n  function persist() { [\"base\",\"plan\"].forEach((id) => localStorage.setItem(\"bouncr_dash_\" + id, $(id).value)); }\n\n  const authHeaders = () => (token ? { authorization: \"Bearer \" + token } : {});\n  const base = () => $(\"base\").value.replace(/\\/$/, \"\");\n  const api = (path) => fetch(base() + path, { headers: authHeaders() }).then(guard);\n  const apiPost = (path, body) =>\n    fetch(base() + path, { method: \"POST\", headers: { \"content-type\": \"application/json\", ...authHeaders() }, body: JSON.stringify(body || {}) }).then(guard);\n  // A 401 anywhere means the session expired/invalid — drop back to login.\n  function guard(res) { if (res.status === 401) { logout(); throw new Error(\"session expired — log in again\"); } return res; }\n\n  function showAuthed(name) {\n    MERCHANT = name && name.id ? name.id : MERCHANT;\n    $(\"who\").textContent = (name && name.name) ? name.name : MERCHANT || \"\";\n    $(\"login\").style.display = \"none\";\n    $(\"authed\").style.display = \"flex\";\n  }\n  function logout() {\n    token = null; MERCHANT = null; localStorage.removeItem(TKEY);\n    $(\"authed\").style.display = \"none\";\n    $(\"login\").style.display = \"flex\";\n    $(\"key\").value = \"\";\n  }\n\n  $(\"login\").addEventListener(\"submit\", async (e) => {\n    e.preventDefault();\n    const key = $(\"key\").value.trim();\n    if (!key) return;\n    $(\"login-status\").textContent = \"signing in…\";\n    try {\n      const r = await fetch(base() + \"/v1/auth/login\", {\n        method: \"POST\", headers: { \"content-type\": \"application/json\" }, body: JSON.stringify({ key }),\n      });\n      const d = await r.json();\n      if (!r.ok) throw new Error(d.error || \"login failed\");\n      token = d.token; localStorage.setItem(TKEY, token);\n      $(\"login-status\").textContent = \"\";\n      showAuthed(d.merchant);\n      enter();\n    } catch (err) { $(\"login-status\").innerHTML = '<span class=\"err\">' + err.message + \"</span>\"; }\n  });\n  $(\"logout\").onclick = logout;\n\n  // Rotate the merchant API key — shows the new one once; old key dies immediately.\n  $(\"rotate-btn\").onclick = async () => {\n    if (!confirm(\"Rotate your API key? Your current key will stop working immediately.\")) return;\n    $(\"rotate-btn\").disabled = true;\n    try {\n      const r = guard(await fetch(base() + \"/v1/auth/rotate-key\", { method: \"POST\", headers: authHeaders() }));\n      const d = await r.json();\n      if (!r.ok) throw new Error(d.error || \"rotation failed\");\n      $(\"newkey-val\").textContent = d.key;\n      $(\"newkey-box\").style.display = \"block\";\n      $(\"rotate-warn\").style.display = \"block\";\n    } catch (e) { alert(e.message); }\n    finally { $(\"rotate-btn\").disabled = false; }\n  };\n  $(\"copy-newkey\").onclick = (e) => {\n    e.preventDefault();\n    if (navigator.clipboard) navigator.clipboard.writeText($(\"newkey-val\").textContent);\n    e.target.textContent = \"Copied\"; setTimeout(() => (e.target.textContent = \"Copy\"), 1200);\n  };\n\n  // Populate the plan dropdown from the merchant's own plans (scoped server-side).\n  async function loadPlans() {\n    const sel = $(\"plan\");\n    try {\n      const r = await (await api(\"/v1/plans\")).json();\n      const plans = r.plans || [];\n      PLANS = plans;\n      sel.innerHTML = \"\";\n      if (!plans.length) { $(\"no-plans\").style.display = \"inline\"; sel.style.display = \"none\"; $(\"edit-panel\").style.display = \"none\"; return false; }\n      $(\"no-plans\").style.display = \"none\"; sel.style.display = \"\"; $(\"edit-panel\").style.display = \"\";\n      for (const p of plans) {\n        const o = document.createElement(\"option\");\n        o.value = p.id;\n        const product = p.persona && p.persona.product_name ? p.persona.product_name : p.id;\n        o.textContent = product + \" · $\" + p.list_price + \"/mo\" + (p.active ? \"\" : \" (inactive)\");\n        sel.appendChild(o);\n      }\n      const last = localStorage.getItem(\"bouncr_dash_plan\");\n      if (last && plans.some((p) => p.id === last)) sel.value = last;\n      fillEdit(sel.value);\n      return true;\n    } catch (_) { return false; }\n  }\n\n  // Populate the edit form from the currently-selected plan.\n  function fillEdit(id) {\n    const p = PLANS.find((x) => x.id === id);\n    if (!p) return;\n    $(\"e-product\").value = (p.persona && p.persona.product_name) || \"\";\n    $(\"e-persona\").value = (p.persona && p.persona.name) || \"\";\n    $(\"e-style\").value = (p.persona && p.persona.style) || \"sassy\";\n    $(\"e-list\").value = p.list_price;\n    $(\"e-floor\").value = p.floor_price;\n    $(\"e-target\").value = p.target_price;\n    $(\"e-fee\").value = p.application_fee_percent == null ? \"\" : p.application_fee_percent;\n    const tg = $(\"toggle-active\");\n    tg.textContent = p.active ? \"Deactivate plan\" : \"Reactivate plan\";\n    tg.style.color = p.active ? \"var(--err)\" : \"var(--ok)\";\n    tg.style.borderColor = p.active ? \"rgba(248,113,113,.4)\" : \"rgba(52,211,153,.4)\";\n    $(\"edit-err\").textContent = \"\"; $(\"edit-status\").textContent = \"\";\n  }\n\n  // Deactivate / reactivate the selected plan. Deactivating stops its embed from\n  // accepting new negotiations (the widget can't resolve an inactive plan), but\n  // it stays in the dashboard so it can be turned back on.\n  $(\"toggle-active\").onclick = async () => {\n    const p = PLANS.find((x) => x.id === $(\"plan\").value);\n    if (!p) return;\n    const next = !p.active;\n    if (!next && !confirm(\"Deactivate this plan? Its embed will stop accepting new negotiations.\")) return;\n    $(\"edit-err\").textContent = \"\"; $(\"edit-status\").textContent = next ? \"reactivating…\" : \"deactivating…\";\n    try {\n      const r = guard(await fetch(base() + \"/v1/plans/\" + encodeURIComponent(p.id), {\n        method: \"PATCH\", headers: { \"content-type\": \"application/json\", ...authHeaders() }, body: JSON.stringify({ active: next }),\n      }));\n      const d = await r.json();\n      if (!r.ok) throw new Error(d.error || \"could not update\");\n      $(\"edit-status\").textContent = next ? \"reactivated ✓\" : \"deactivated ✓\";\n      await loadPlans();\n      $(\"plan\").value = d.plan.id; fillEdit(d.plan.id); load();\n    } catch (err) { $(\"edit-status\").textContent = \"\"; $(\"edit-err\").textContent = err.message; }\n  };\n\n  $(\"edit-form\").addEventListener(\"submit\", async (e) => {\n    e.preventDefault();\n    $(\"edit-err\").textContent = \"\"; $(\"edit-status\").textContent = \"saving…\";\n    const numv = (id) => { const v = parseFloat($(id).value); return Number.isFinite(v) ? v : null; };\n    const feeRaw = $(\"e-fee\").value.trim();\n    const body = {\n      product_name: $(\"e-product\").value.trim(),\n      persona_name: $(\"e-persona\").value.trim(),\n      persona_style: $(\"e-style\").value,\n      list_price: numv(\"e-list\"),\n      floor_price: numv(\"e-floor\"),\n      target_price: numv(\"e-target\"),\n      application_fee_percent: feeRaw === \"\" ? null : parseFloat(feeRaw),\n    };\n    try {\n      const r = guard(await fetch(base() + \"/v1/plans/\" + encodeURIComponent($(\"plan\").value), {\n        method: \"PATCH\", headers: { \"content-type\": \"application/json\", ...authHeaders() }, body: JSON.stringify(body),\n      }));\n      const d = await r.json();\n      if (!r.ok) throw new Error(d.error || \"could not save\");\n      $(\"edit-status\").textContent = \"saved ✓\";\n      const keep = d.plan.id;\n      await loadPlans();\n      $(\"plan\").value = keep; fillEdit(keep);\n      load(); // re-render with the new prices / reference lines\n    } catch (err) { $(\"edit-status\").textContent = \"\"; $(\"edit-err\").textContent = err.message; }\n  });\n  // After auth: load the merchant's plans, then render the selected one.\n  async function enter() {\n    const has = await loadPlans();\n    if (has) load();\n    else { $(\"funnel\").innerHTML = \"\"; $(\"closing\").innerHTML = \"\"; $(\"sessions\").innerHTML = \"\"; $(\"status\").textContent = \"\"; }\n  }\n  $(\"plan\").onchange = () => { fillEdit($(\"plan\").value); load(); };\n\n  function card(label, value) { return `<div class=\"card\"><h3>${label}</h3><div class=\"big\">${value}</div></div>`; }\n\n  async function load() {\n    persist();\n    $(\"status\").textContent = \"loading…\";\n    try {\n      const a = await (await api(\"/v1/analytics/wtp?plan_id=\" + encodeURIComponent($(\"plan\").value))).json();\n      if (a.error) throw new Error(a.error);\n      renderFunnel(a); renderClosing(a); renderTactics(a); renderHist(a);\n      await renderSessions();\n      await renderConnect();\n      await renderLint();\n      $(\"status\").textContent = \"\";\n    } catch (e) { $(\"status\").innerHTML = '<span class=\"err\">' + e.message + \"</span>\"; }\n  }\n\n  function renderFunnel(a) {\n    const f = a.funnel;\n    $(\"funnel\").innerHTML =\n      card(\"Sessions\", f.sessions) + card(\"Engaged\", f.engaged) +\n      card(\"Accepted\", f.accepted) + card(\"Settled\", f.settled) +\n      card(\"Walk rate\", pct(walks(f) , f.sessions));\n  }\n  function walks(f) { return Object.values(f.walkByRound).reduce((x, y) => x + y, 0); }\n  function pct(n, d) { return d ? Math.round((100 * n) / d) + \"%\" : \"—\"; }\n\n  function renderClosing(a) {\n    const c = a.closing, m = a.monetization || { takeRatePercent: 0, bouncrFee: 0, merchantNet: c.revenue };\n    $(\"closing\").innerHTML =\n      card(\"Median price\", c.medianPrice != null ? \"$\" + c.medianPrice : \"—\") +\n      card(\"Avg rounds\", c.avgRoundsToClose != null ? c.avgRoundsToClose : \"—\") +\n      card(\"Revenue\", \"$\" + c.revenue) +\n      card(\"Bouncr take (\" + m.takeRatePercent + \"%)\", \"$\" + m.bouncrFee) +\n      card(\"Your net\", \"$\" + m.merchantNet) +\n      card(\"Capture vs list\", c.upliftPct != null ? c.upliftPct + \"%\" : \"—\");\n    // Settlement panel take-rate line.\n    $(\"take-rate\").textContent = m.takeRatePercent + \"%\";\n    $(\"take-note\").textContent = m.takeRatePercent > 0\n      ? \"of each settled invoice → Bouncr (Connect application fee)\"\n      : \"no platform fee on this plan\";\n  }\n\n  function renderTactics(a) {\n    const t = a.tactics, keys = Object.keys(t).sort((x, y) => t[y] - t[x]);\n    $(\"tactics\").innerHTML = keys.length\n      ? keys.map((k) => `<div><span style=\"width:140px;display:inline-block\">${k}</span><span class=\"tb\" style=\"width:${Math.max(6, t[k] * 200)}px\"></span><span class=\"meta\">${Math.round(t[k]*100)}%</span></div>`).join(\"\")\n      : '<span class=\"meta\">No tactics recorded yet.</span>';\n  }\n\n  function renderHist(a) {\n    const ref = a.reference;\n    const data = a.offers.firstOffers.concat(a.offers.closingPrices);\n    const cv = $(\"hist\"); const ctx = cv.getContext(\"2d\");\n    const W = cv.width = cv.clientWidth * 2, H = cv.height = 440; ctx.scale(1,1);\n    ctx.clearRect(0, 0, W, H);\n    const max = Math.max(ref.anchor * 1.1, ...(data.length ? data : [ref.anchor]));\n    const bins = 24, counts = new Array(bins).fill(0);\n    for (const v of data) { const i = Math.min(bins - 1, Math.floor((v / max) * bins)); counts[i]++; }\n    const peak = Math.max(1, ...counts);\n    const pad = 30, bw = (W - pad * 2) / bins;\n    // bars\n    ctx.fillStyle = \"#7C3AED\";\n    counts.forEach((n, i) => { const h = (n / peak) * (H - pad * 2); ctx.fillRect(pad + i * bw + 2, H - pad - h, bw - 4, h); });\n    // reference lines\n    const lineAt = (val, color, label) => {\n      const x = pad + (val / max) * (W - pad * 2);\n      ctx.strokeStyle = color; ctx.lineWidth = 2; ctx.setLineDash([5, 4]);\n      ctx.beginPath(); ctx.moveTo(x, pad / 2); ctx.lineTo(x, H - pad); ctx.stroke(); ctx.setLineDash([]);\n      ctx.fillStyle = color; ctx.font = \"20px sans-serif\"; ctx.fillText(label, x + 3, pad);\n    };\n    lineAt(ref.floor, \"#f87171\", \"floor $\" + ref.floor);   // red — the line you never cross\n    lineAt(ref.target, \"#34D399\", \"target $\" + ref.target); // mint — the goal / win line\n    lineAt(ref.list, \"#8b8b99\", \"list $\" + ref.list);      // gray — reference\n    $(\"hist-legend\").innerHTML = `Bars: first offers + closing prices (n=${data.length}). Lines: floor / target / list.`;\n  }\n\n  async function renderSessions() {\n    const r = await (await api(\"/v1/plans/\" + encodeURIComponent($(\"plan\").value) + \"/sessions\")).json();\n    const rows = (r.sessions || []).slice(0, 25).map((s) =>\n      `<tr class=\"session\" data-id=\"${s.id}\"><td>${s.end_user_ref}</td><td><span class=\"pill ${s.status}\">${s.status}</span></td><td>${s.round}</td><td>$${s.current_ask}</td></tr>`).join(\"\");\n    $(\"sessions\").innerHTML = rows || '<tr><td colspan=\"4\" class=\"meta\">No sessions yet.</td></tr>';\n    document.querySelectorAll(\"tr.session\").forEach((tr) => tr.onclick = () => openTranscript(tr.dataset.id));\n  }\n\n  async function openTranscript(id) {\n    const r = await (await api(\"/v1/sessions/\" + id + \"/transcript\")).json();\n    $(\"drawer-title\").textContent = (r.session.end_user_ref || \"session\") + \" · \" + r.session.status;\n    $(\"transcript\").innerHTML = (r.turns || []).map((t) => {\n      const meta = t.extracted ? `intent: ${t.extracted.intent}${t.extracted.offer_amount != null ? \" · offer $\" + t.extracted.offer_amount : \"\"}${t.extracted.tactics && t.extracted.tactics.length ? \" · \" + t.extracted.tactics.join(\"/\") : \"\"}`\n        : t.action ? \"→ \" + t.action.type + (t.action.amount != null ? \" $\" + t.action.amount : \"\") : \"\";\n      return `<div class=\"msg ${t.role === \"user\" ? \"user\" : \"bot\"}\">${escapeHtml(t.text)}</div>` + (meta ? `<div class=\"meta\">${meta}</div>` : \"\");\n    }).join(\"\");\n    $(\"drawer\").classList.add(\"open\");\n  }\n\n  async function renderConnect() {\n    try {\n      const s = await (await api(\"/v1/merchants/\" + encodeURIComponent(MERCHANT) + \"/connect\")).json();\n      const b = $(\"connect-badge\");\n      if (s.connected && s.charges_enabled) { b.className = \"badge ok\"; b.textContent = \"connected · ready\"; $(\"connect-btn\").style.display = \"none\"; }\n      else if (s.connected) { b.className = \"badge no\"; b.textContent = \"onboarding incomplete\"; }\n      else { b.className = \"badge no\"; b.textContent = \"not connected — deals settle to platform\"; }\n    } catch (_) {}\n  }\n\n  async function renderLint() {\n    try {\n      const l = await (await api(\"/v1/plans/\" + encodeURIComponent($(\"plan\").value) + \"/lint\")).json();\n      const out = (l.errors || []).map((e) => `<div class=\"e\">⛔ ${e}</div>`).concat((l.warnings || []).map((w) => `<div class=\"w\">⚠️ ${w}</div>`));\n      $(\"lint\").innerHTML = out.length ? out.join(\"\") : '<span class=\"meta\">Config lints clean.</span>';\n    } catch (_) {}\n  }\n\n  $(\"connect-btn\").onclick = async () => {\n    const r = await (await apiPost(\"/v1/merchants/\" + encodeURIComponent(MERCHANT) + \"/connect/onboard\", { return_url: location.href })).json();\n    if (r.url) window.open(r.url, \"_blank\"); else alert(r.error || \"could not start onboarding\");\n  };\n\n  function escapeHtml(s) { return String(s).replace(/[&<>]/g, (c) => ({ \"&\": \"&amp;\", \"<\": \"&lt;\", \">\": \"&gt;\" }[c])); }\n  $(\"refresh\").onclick = load;\n\n  // Boot: if we have a token, validate it (and learn the merchant) before showing\n  // the dashboard; otherwise show the login form.\n  (async () => {\n    if (!token) { logout(); return; }\n    try {\n      const r = await fetch(base() + \"/v1/auth/me\", { headers: authHeaders() });\n      if (!r.ok) { logout(); return; }\n      showAuthed((await r.json()).merchant);\n      enter();\n    } catch (_) { logout(); }\n  })();\n})();\n</script>\n</body>\n</html>\n";
export const LANDING_HTML: string = "<!doctype html>\n<html lang=\"en\">\n<head>\n<meta charset=\"utf-8\" />\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n<title>Bouncr — your paywall should haggle</title>\n<meta name=\"description\" content=\"A drop-in AI bouncer that negotiates each user's price — with a policy engine that guarantees you never sell below cost. Negotiated subscription pricing, as infrastructure.\" />\n<meta property=\"og:title\" content=\"Bouncr — your paywall should haggle\" />\n<meta property=\"og:description\" content=\"A drop-in negotiation agent for any subscription app. The bouncer that can't be jailbroken.\" />\n<link rel=\"icon\" type=\"image/svg+xml\" href=\"data:image/svg+xml;base64,\" />\n<link rel=\"apple-touch-icon\" href=\"data:image/png;base64,\" />\n<link rel=\"preconnect\" href=\"https://fonts.googleapis.com\" />\n<link rel=\"preconnect\" href=\"https://fonts.gstatic.com\" crossorigin />\n<link href=\"https://fonts.googleapis.com/css2?family=Plus+Jakarta+Sans:wght@600;700;800&family=Space+Grotesk:wght@400;500;600;700&display=swap\" rel=\"stylesheet\" />\n<style>\n  :root {\n    --bg: #0B0B12;       /* noir — near-black, violet-tinted, never pure white */\n    --bg2: #101019;\n    --panel: #15151f;\n    --line: #23232e;\n    --text: #ECECF1;\n    --muted: #8b8b99;\n    --accent: #7C3AED;   /* electric violet — the persona / brand color */\n    --accent2: #a78bfa;\n    --hi: #C4B5FD;       /* light-violet highlight (premium sheen, on-palette) */\n    /* deal mint (#34D399) is reserved for the deal-reached moment — it lives in\n       the embedded widget, NOT in the landing chrome. No green out here. */\n    --maxw: 1080px;\n  }\n  * { box-sizing: border-box; }\n  html { scroll-behavior: smooth; }\n  body {\n    margin: 0; background: var(--bg); color: var(--text);\n    font-family: \"Space Grotesk\", ui-sans-serif, system-ui, -apple-system, sans-serif;\n    -webkit-font-smoothing: antialiased; line-height: 1.5; overflow-x: hidden;\n  }\n  a { color: inherit; text-decoration: none; }\n  .wrap { max-width: var(--maxw); margin: 0 auto; padding: 0 24px; }\n  .accent { color: var(--accent2); }\n  .hi { color: var(--hi); }\n\n  /* glow backdrop */\n  .glow { position: fixed; inset: 0; z-index: 0; pointer-events: none; overflow: hidden; }\n  .glow::before {\n    content: \"\"; position: absolute; top: -20%; left: 50%; transform: translateX(-50%);\n    width: 900px; height: 700px; border-radius: 50%;\n    background: radial-gradient(closest-side, rgba(124,58,237,0.28), transparent 70%);\n    filter: blur(20px);\n  }\n\n  /* nav */\n  nav {\n    position: sticky; top: 0; z-index: 50; backdrop-filter: blur(10px);\n    background: rgba(11,11,15,0.7); border-bottom: 1px solid var(--line);\n  }\n  nav .wrap { display: flex; align-items: center; gap: 20px; height: 64px; }\n  .logo { display: flex; align-items: center; gap: 11px; }\n  .logo-icon { width: 42px; height: 42px; display: block; flex: 0 0 auto; }\n  .logo-word { font-family: \"Plus Jakarta Sans\", system-ui, sans-serif; font-weight: 800; font-size: 26px; color: #fff; letter-spacing: -0.5px; line-height: 1; }\n  .logo.sm .logo-icon { width: 34px; height: 34px; }\n  .logo.sm .logo-word { font-size: 21px; }\n  nav .links { margin-left: auto; display: flex; align-items: center; gap: 26px; font-size: 14px; color: var(--muted); }\n  nav .links a:hover { color: var(--text); }\n  .btn {\n    display: inline-flex; align-items: center; gap: 8px; border-radius: 11px; padding: 10px 17px;\n    font-weight: 600; font-size: 14px; cursor: pointer; border: 1px solid transparent; transition: .15s;\n    background: transparent; /* <button> elements default to a light UA fill — kill it */\n    font-family: inherit;\n  }\n  .btn-primary { background: var(--accent); color: #fff; }\n  .btn-primary:hover { background: #8b4ff0; transform: translateY(-1px); }\n  .btn-ghost { background: transparent; border-color: var(--line); color: var(--text); }\n  .btn-ghost:hover { border-color: var(--accent); color: #fff; background: rgba(124,58,237,.12); }\n\n  section { position: relative; z-index: 1; }\n\n  /* hero */\n  .hero { padding: 76px 0 40px; }\n  .hero-grid { display: grid; grid-template-columns: 1.05fr 0.95fr; gap: 48px; align-items: center; }\n  .eyebrow {\n    display: inline-flex; align-items: center; gap: 8px; font-size: 12.5px; color: var(--accent2);\n    border: 1px solid var(--line); border-radius: 999px; padding: 5px 13px; margin-bottom: 22px;\n    background: rgba(124,58,237,0.06);\n  }\n  h1 { font-size: clamp(40px, 6vw, 66px); line-height: 1.02; letter-spacing: -2px; margin: 0 0 20px; font-weight: 700; }\n  h1 em { font-style: normal; background: linear-gradient(120deg, var(--accent), var(--hi)); -webkit-background-clip: text; background-clip: text; color: transparent; }\n  .lede { font-size: 18.5px; color: var(--muted); max-width: 30em; margin: 0 0 28px; }\n  .lede b { color: var(--text); font-weight: 600; }\n  .cta-row { display: flex; gap: 12px; flex-wrap: wrap; align-items: center; }\n  .cta-row .note { font-size: 13px; color: var(--muted); }\n\n  /* early-access inline email capture (no mailto — type it right here) */\n  .waitlist { position: relative; }\n  .wl-form { display: none; align-items: center; gap: 6px; background: var(--panel); border: 1px solid var(--line); border-radius: 11px; padding: 4px 4px 4px 15px; }\n  .waitlist.editing #wl-open { display: none; }\n  .waitlist.editing .wl-form { display: inline-flex; }\n  .wl-form input { background: transparent; border: 0; outline: none; color: var(--text); font: inherit; font-size: 14.5px; width: 210px; }\n  .wl-form input::placeholder { color: var(--muted); }\n  .wl-go { background: var(--accent); color: #fff; border: 0; border-radius: 9px; min-width: 36px; height: 36px; font-size: 17px; font-weight: 700; cursor: pointer; transition: .15s; }\n  .wl-go:hover { background: #8b4ff0; }\n  .wl-go:disabled { opacity: .55; cursor: default; }\n  .wl-done { display: none; font-weight: 600; font-size: 14.5px; color: var(--accent2); }\n  .waitlist.done #wl-open, .waitlist.done .wl-form { display: none; }\n  .waitlist.done .wl-done { display: inline-flex; align-items: center; }\n\n  /* demo panel */\n  .demo-card {\n    border: 1px solid var(--line); border-radius: 20px; overflow: hidden;\n    background: var(--panel); box-shadow: 0 30px 80px rgba(0,0,0,.5), 0 0 0 1px rgba(124,58,237,.08);\n  }\n  .demo-head { display: flex; align-items: center; gap: 9px; padding: 12px 16px; border-bottom: 1px solid var(--line); background: #13131b; }\n  .demo-head .lights { display: flex; gap: 6px; }\n  .demo-head .lights i { width: 11px; height: 11px; border-radius: 50%; display: block; }\n  .demo-head .lights i { background:#34343f } /* neutral window chrome — keep green out, mint is for the close only */\n  .demo-head .url { margin-left: 8px; font-size: 12.5px; color: var(--muted); }\n  #demo { height: 540px; }\n  #demo iframe { border: 0 !important; }\n\n  /* marquee of authorities */\n  .marquee { border-top: 1px solid var(--line); border-bottom: 1px solid var(--line); padding: 16px 0; margin-top: 56px; overflow: hidden; }\n  .marquee .track { display: flex; gap: 40px; white-space: nowrap; animation: scroll 26s linear infinite; color: var(--muted); font-size: 14px; }\n  .marquee .track span { opacity: .7; }\n  @keyframes scroll { to { transform: translateX(-50%); } }\n\n  /* sections */\n  .band { padding: 84px 0; }\n  .kicker { font-size: 13px; letter-spacing: 2px; text-transform: uppercase; color: var(--accent2); margin-bottom: 14px; }\n  h2 { font-size: clamp(28px, 4vw, 42px); letter-spacing: -1px; margin: 0 0 16px; font-weight: 700; }\n  .band p.sub { color: var(--muted); font-size: 17px; max-width: 38em; margin: 0 0 36px; }\n\n  .three { display: grid; grid-template-columns: repeat(3,1fr); gap: 18px; }\n  .feat { border: 1px solid var(--line); border-radius: 16px; padding: 24px; background: linear-gradient(180deg, var(--bg2), var(--bg)); }\n  .feat .ic { width: 42px; height: 42px; border-radius: 11px; background: rgba(124,58,237,.12); display: grid; place-items: center; font-size: 20px; margin-bottom: 16px; }\n  .feat h3 { margin: 0 0 8px; font-size: 18px; }\n  .feat p { margin: 0; color: var(--muted); font-size: 14.5px; }\n\n  .split { display: grid; grid-template-columns: 1fr 1fr; gap: 40px; align-items: center; }\n  .quote { border-left: 3px solid var(--accent); padding: 6px 0 6px 22px; font-size: 20px; color: var(--text); }\n  .quote span { color: var(--muted); font-size: 14px; display: block; margin-top: 10px; }\n\n  .jail { text-align: center; max-width: 760px; margin: 0 auto; }\n  .jail .pill { display: inline-block; font-size: 12.5px; color: var(--accent2); border: 1px solid rgba(124,58,237,.32); background: rgba(124,58,237,.08); border-radius: 999px; padding: 5px 13px; margin-bottom: 20px; }\n  .flow { display: flex; align-items: center; justify-content: center; gap: 10px; flex-wrap: wrap; margin-top: 28px; font-size: 13.5px; }\n  .flow .node { border: 1px solid var(--line); border-radius: 10px; padding: 9px 14px; background: var(--panel); }\n  .flow .node.eng { border-color: var(--accent); color: var(--accent2); }\n  .flow .arr { color: var(--muted); }\n\n  /* install */\n  .install { display: grid; grid-template-columns: 1fr 1fr; gap: 40px; align-items: center; }\n  pre { margin: 0; background: #0d0d13; border: 1px solid var(--line); border-radius: 14px; padding: 20px; overflow-x: auto; font-size: 13.5px; line-height: 1.7; font-family: ui-monospace, \"SF Mono\", Menlo, monospace; }\n  pre .tok-tag { color: #ff7b9c; } pre .tok-attr { color: var(--accent2); } pre .tok-str { color: var(--hi); } pre .tok-com { color: #5a5a6a; }\n  .steps { list-style: none; padding: 0; margin: 0; display: grid; gap: 16px; }\n  .steps li { display: flex; gap: 14px; align-items: flex-start; }\n  .steps .n { flex: 0 0 28px; height: 28px; border-radius: 8px; background: rgba(124,58,237,.14); color: var(--accent2); display: grid; place-items: center; font-weight: 700; font-size: 14px; }\n  .steps b { display: block; margin-bottom: 2px; }\n  .steps p { margin: 0; color: var(--muted); font-size: 14px; }\n\n  /* final cta */\n  .final { text-align: center; padding: 96px 0; }\n  .final .box { border: 1px solid var(--line); border-radius: 24px; padding: 56px 32px; background: radial-gradient(120% 140% at 50% 0%, rgba(124,58,237,.16), transparent 60%); }\n  .final h2 { margin-bottom: 14px; }\n\n  footer { border-top: 1px solid var(--line); padding: 36px 0; color: var(--muted); font-size: 13.5px; }\n  footer .wrap { display: flex; justify-content: space-between; align-items: center; flex-wrap: wrap; gap: 12px; }\n  .mark b { color: var(--accent2); }\n  /* DAED developer credit — Apple system font; the æ is sized up to read as a logo */\n  .dev-credit { display: inline-flex; align-items: center; gap: 11px; font-family: -apple-system, BlinkMacSystemFont, \"SF Pro Text\", \"Segoe UI\", Helvetica, Arial, sans-serif; font-size: 13px; color: var(--muted); }\n  .dev-credit .aelig { font-family: -apple-system, BlinkMacSystemFont, \"SF Pro Display\", \"Segoe UI\", Helvetica, Arial, sans-serif; font-size: 38px; font-weight: 600; line-height: 1; letter-spacing: -1px; color: var(--text); }\n\n  @media (max-width: 860px) {\n    .hero-grid, .split, .install { grid-template-columns: 1fr; }\n    .three { grid-template-columns: 1fr; }\n    nav .links a:not(.btn) { display: none; }\n    .hero { padding: 44px 0 20px; }\n  }\n</style>\n</head>\n<body>\n<div class=\"glow\"></div>\n\n<nav>\n  <div class=\"wrap\">\n    <a class=\"logo\" href=\"/\" aria-label=\"Bouncr home\"><svg class=\"logo-icon\" viewBox=\"0 0 100 100\" aria-hidden=\"true\"><rect x=\"8\" y=\"8\" width=\"84\" height=\"84\" rx=\"24\" fill=\"#7C3AED\"/><circle cx=\"50\" cy=\"34\" r=\"10\" fill=\"#0B0B12\"/><path d=\"M27 64 L73 53\" stroke=\"#0B0B12\" stroke-width=\"11\" stroke-linecap=\"round\" fill=\"none\"/><path d=\"M27 53 L73 64\" stroke=\"#0B0B12\" stroke-width=\"11\" stroke-linecap=\"round\" fill=\"none\"/></svg><span class=\"logo-word\">Bouncr</span></a>\n    <div class=\"links\">\n      <a href=\"#how\">How it works</a>\n      <a href=\"#demo-section\">Try it</a>\n      <a href=\"#install\">Install</a>\n      <a class=\"btn btn-primary\" href=\"#demo-section\">Talk to Vini</a>\n    </div>\n  </div>\n</nav>\n\n<section class=\"hero\">\n  <div class=\"wrap hero-grid\">\n    <div>\n      <span class=\"eyebrow\">● Negotiated pricing, as infrastructure</span>\n      <h1>Your paywall should <em>haggle.</em></h1>\n      <p class=\"lede\">Bouncr is a drop-in AI negotiation agent that lets any subscription app offer personalized, haggled pricing — backed by a <b>deterministic policy engine</b> that guarantees you never sell below cost.</p>\n      <div class=\"cta-row\">\n        <a class=\"btn btn-primary\" href=\"#demo-section\">Try the bouncer →</a>\n        <a class=\"btn btn-ghost\" href=\"#install\">Drop it in, in 10 min</a>\n        <span class=\"note\">no signup · haggle live below</span>\n      </div>\n    </div>\n    <div class=\"demo-card\" id=\"demo-section\">\n      <div class=\"demo-head\">\n        <span class=\"lights\"><i></i><i></i><i></i></span>\n        <span class=\"url\">obius.io · membership</span>\n      </div>\n      <div id=\"demo\"></div>\n    </div>\n  </div>\n\n  <div class=\"marquee\">\n    <div class=\"track\">\n      <span>“checked with the suits…”</span><span>“ran it by the math nerds…”</span><span>“talked to my boss…”</span><span>“the bean counters said no…”</span><span>“above my pay grade…”</span><span>“that's the floor, take it…”</span>\n      <span>“checked with the suits…”</span><span>“ran it by the math nerds…”</span><span>“talked to my boss…”</span><span>“the bean counters said no…”</span><span>“above my pay grade…”</span><span>“that's the floor, take it…”</span>\n    </div>\n  </div>\n</section>\n\n<section class=\"band\" id=\"why\">\n  <div class=\"wrap split\">\n    <div>\n      <div class=\"kicker\">Flat pricing is broken</div>\n      <h2>Light users overpay. Heavy users bleed you dry.</h2>\n      <p class=\"sub\">AI-era products have per-user costs that swing <b style=\"color:var(--text)\">10–50×</b>. One power user can take an indie founder's bill from $127 to $890 a month, while light users quietly overpay and churn. A static pricing page captures <em>zero</em> information about what anyone would actually pay.</p>\n    </div>\n    <div>\n      <div class=\"quote\">\n        Subscription prices have gotten outrageous — and you pay the same flat rate whether you live in the product or barely open it. If you use less, you should get to pay <b>less</b>.\n        <span>Somehow that became a radical idea. We made it the default.</span>\n      </div>\n    </div>\n  </div>\n</section>\n\n<section class=\"band\" id=\"how\" style=\"background:var(--bg2); border-top:1px solid var(--line); border-bottom:1px solid var(--line);\">\n  <div class=\"wrap\">\n    <div class=\"kicker\">One product, three layers</div>\n    <h2>The bouncer out front. The math in the back.</h2>\n    <p class=\"sub\">Stripe handles your payments. Orb meters your usage. Bouncr discovers what each user will actually pay — and closes the deal.</p>\n    <div class=\"three\">\n      <div class=\"feat\">\n        <div class=\"ic\">💬</div>\n        <h3>Negotiation agent</h3>\n        <p>An embeddable chat that haggles in character — sassy, persistent, screenshot-worthy. It feels like texting a real bouncer at the door.</p>\n      </div>\n      <div class=\"feat\">\n        <div class=\"ic\">⚖️</div>\n        <h3>Policy engine</h3>\n        <p>Pure deterministic code sets every price. Cost floors, concession curves, reasoning tiers. The LLM never touches the number that gets charged.</p>\n      </div>\n      <div class=\"feat\">\n        <div class=\"ic\">📈</div>\n        <h3>WTP analytics</h3>\n        <p>Every offer, walk-away, and close — your true demand curve, often for the first time. The data exhaust no billing platform has.</p>\n      </div>\n    </div>\n  </div>\n</section>\n\n<section class=\"band\">\n  <div class=\"wrap jail\">\n    <span class=\"pill\">✓ Architecturally jailbreak-proof</span>\n    <h2>Argue with it for days. You'll get charm, not a discount.</h2>\n    <p class=\"sub\" style=\"margin-left:auto;margin-right:auto\">The LLM and the numbers never touch. It converses and extracts your offer into structured data — a separate, deterministic engine decides accept / counter / hold / walk, and tells the bouncer only what it's allowed to say. A validator catches any number it tries to invent. The price can't be talked below the floor, because the floor lives in code, not a prompt.</p>\n    <div class=\"flow\">\n      <span class=\"node\">you</span><span class=\"arr\">→</span>\n      <span class=\"node\">extractor</span><span class=\"arr\">→</span>\n      <span class=\"node eng\">policy engine</span><span class=\"arr\">→</span>\n      <span class=\"node\">persona</span><span class=\"arr\">→</span>\n      <span class=\"node\">validator</span><span class=\"arr\">→</span>\n      <span class=\"node\">your price</span>\n    </div>\n  </div>\n</section>\n\n<section class=\"band\" id=\"install\" style=\"background:var(--bg2); border-top:1px solid var(--line); border-bottom:1px solid var(--line);\">\n  <div class=\"wrap install\">\n    <div>\n      <div class=\"kicker\">Drop-in</div>\n      <h2>One tag. Any stack.</h2>\n      <p class=\"sub\">A script-tag loader drops a sandboxed widget onto your pricing page. Your server mints a session, the widget haggles inside your guardrails, and the closed deal hands off to Stripe.</p>\n      <ol class=\"steps\">\n        <li><span class=\"n\">1</span><div><b>Add the tag</b><p>One line on your pricing page — it mounts the bouncer in an iframe.</p></div></li>\n        <li><span class=\"n\">2</span><div><b>Set your guardrails</b><p>List price, floor, target, concession curve, persona. The engine never breaches them.</p></div></li>\n        <li><span class=\"n\">3</span><div><b>Settle into Stripe</b><p>Closed deals create a subscription at the negotiated price. You never touch money — or PCI.</p></div></li>\n      </ol>\n    </div>\n    <div>\n<pre><span class=\"tok-com\">&lt;!-- on your pricing page --&gt;</span>\n<span class=\"tok-tag\">&lt;script</span> <span class=\"tok-attr\">src</span>=<span class=\"tok-str\">\"https://bouncr.tech/embed.js\"</span>\n        <span class=\"tok-attr\">data-plan</span>=<span class=\"tok-str\">\"pro_monthly\"</span>\n        <span class=\"tok-attr\">data-user</span>=<span class=\"tok-str\">\"user_123\"</span>\n        <span class=\"tok-attr\">data-mount</span>=<span class=\"tok-str\">\"#bouncr\"</span><span class=\"tok-tag\">&gt;&lt;/script&gt;</span>\n\n<span class=\"tok-com\">// or wire it up yourself</span>\n<span class=\"tok-attr\">Bouncr</span>.mount({\n  el: <span class=\"tok-str\">\"#bouncr\"</span>,\n  planId: <span class=\"tok-str\">\"pro_monthly\"</span>,\n  userRef: user.id,\n  onDeal: (d) =&gt; location = d.checkoutUrl,\n})</pre>\n    </div>\n  </div>\n</section>\n\n<section class=\"final\">\n  <div class=\"wrap\">\n    <div class=\"box\">\n      <h2>Stop guessing what they'd pay.</h2>\n      <p class=\"sub\" style=\"margin:0 auto 28px\">Put a bouncer on your door. Watch your real demand curve draw itself.</p>\n      <div class=\"cta-row\" style=\"justify-content:center\">\n        <a class=\"btn btn-primary\" href=\"#demo-section\">Haggle with the demo</a>\n        <span class=\"waitlist\" id=\"waitlist\">\n          <button class=\"btn btn-ghost\" id=\"wl-open\" type=\"button\">Get early access</button>\n          <form class=\"wl-form\" id=\"wl-form\" novalidate>\n            <input id=\"wl-email\" type=\"email\" inputmode=\"email\" autocomplete=\"email\" placeholder=\"you@company.com\" aria-label=\"Your email\" required />\n            <button class=\"wl-go\" type=\"submit\" aria-label=\"Join the waitlist\">→</button>\n          </form>\n          <span class=\"wl-done\" id=\"wl-done\">you're on the list 🎉</span>\n        </span>\n      </div>\n    </div>\n  </div>\n</section>\n\n<footer>\n  <div class=\"wrap\">\n    <span class=\"logo sm\"><svg class=\"logo-icon\" viewBox=\"0 0 100 100\" aria-hidden=\"true\"><rect x=\"8\" y=\"8\" width=\"84\" height=\"84\" rx=\"24\" fill=\"#7C3AED\"/><circle cx=\"50\" cy=\"34\" r=\"10\" fill=\"#0B0B12\"/><path d=\"M27 64 L73 53\" stroke=\"#0B0B12\" stroke-width=\"11\" stroke-linecap=\"round\" fill=\"none\"/><path d=\"M27 53 L73 64\" stroke=\"#0B0B12\" stroke-width=\"11\" stroke-linecap=\"round\" fill=\"none\"/></svg><span class=\"logo-word\">Bouncr</span></span>\n    <span class=\"dev-credit\"><span class=\"aelig\">æ</span> Developed by DAED</span>\n    <span class=\"mark\">negotiated via <b>Bouncr</b> · thebouncr.com</span>\n  </div>\n</footer>\n\n<script src=\"/embed.js\"></script>\n<script>\n  window.Bouncr && Bouncr.mount({\n    el: \"#demo\",\n    planId: \"pro_monthly\",\n    userRef: \"lp_\" + Math.random().toString(36).slice(2, 9),\n    theme: { accent: \"7C3AED\" },\n    fallbackUrl: \"#install\",\n    onDeal: function (d) {\n      var el = document.getElementById(\"demo\");\n      // keep them on the page — the widget already shows the deal screen\n      try { window.scrollTo({ top: el.getBoundingClientRect().top + window.scrollY - 80, behavior: \"smooth\" }); } catch (e) {}\n    },\n  });\n\n  // Early-access: the button becomes an inline email box — type it, hit enter,\n  // done. No mailto, no leaving the page.\n  (function () {\n    var wl = document.getElementById(\"waitlist\");\n    if (!wl) return;\n    var openBtn = document.getElementById(\"wl-open\");\n    var form = document.getElementById(\"wl-form\");\n    var email = document.getElementById(\"wl-email\");\n    var go = form.querySelector(\".wl-go\");\n    var EMAIL_RE = /^[^\\s@]+@[^\\s@]+\\.[^\\s@]+$/;\n\n    openBtn.addEventListener(\"click\", function () {\n      wl.classList.add(\"editing\");\n      setTimeout(function () { email.focus(); }, 20);\n    });\n    email.addEventListener(\"keydown\", function (e) {\n      if (e.key === \"Escape\") { wl.classList.remove(\"editing\"); openBtn.focus(); }\n    });\n    form.addEventListener(\"submit\", function (e) {\n      e.preventDefault();\n      var v = (email.value || \"\").trim();\n      if (!EMAIL_RE.test(v)) { email.focus(); email.style.outline = \"1px solid #f87171\"; return; }\n      go.disabled = true;\n      fetch(\"/v1/waitlist\", {\n        method: \"POST\",\n        headers: { \"content-type\": \"application/json\" },\n        body: JSON.stringify({ email: v, source: \"thebouncr.com\" }),\n      }).catch(function () {}).then(function () {\n        wl.classList.remove(\"editing\");\n        wl.classList.add(\"done\");\n      });\n    });\n  })();\n</script>\n</body>\n</html>\n";
export const ONBOARD_HTML: string = "<!doctype html>\n<html lang=\"en\">\n<head>\n<meta charset=\"utf-8\" />\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n<title>Get started — Bouncr</title>\n<link rel=\"icon\" type=\"image/svg+xml\" href=\"data:image/svg+xml;base64,\" />\n<style>\n  :root { --bg:#0B0B12; --panel:#15151f; --line:#23232e; --text:#ECECF1; --muted:#8b8b99; --accent:#7C3AED; --accent2:#a78bfa; --mint:#34D399; --err:#f87171; }\n  * { box-sizing: border-box; }\n  body { margin:0; background:var(--bg); color:var(--text); font:15px/1.5 ui-sans-serif, system-ui, -apple-system, sans-serif; }\n  .wrap { max-width:560px; margin:0 auto; padding:40px 22px 80px; }\n  .brand { display:flex; align-items:center; gap:10px; margin-bottom:8px; }\n  .brand svg { width:34px; height:34px; }\n  .brand b { font-size:20px; letter-spacing:-0.4px; }\n  h1 { font-size:26px; letter-spacing:-0.6px; margin:18px 0 4px; }\n  p.sub { color:var(--muted); margin:0 0 24px; }\n  .steps { display:flex; gap:8px; margin-bottom:24px; font-size:12.5px; }\n  .steps .s { flex:1; padding:7px 10px; border:1px solid var(--line); border-radius:9px; color:var(--muted); text-align:center; }\n  .steps .s.on { border-color:var(--accent); color:var(--text); background:rgba(124,58,237,.1); }\n  .steps .s.done { color:var(--mint); border-color:rgba(52,211,153,.3); }\n  .card { background:var(--panel); border:1px solid var(--line); border-radius:16px; padding:22px; }\n  label { display:block; font-size:13px; color:var(--muted); margin:14px 0 5px; }\n  .row { display:flex; gap:12px; }\n  .row > div { flex:1; }\n  input, select { width:100%; background:#0e0e14; border:1px solid var(--line); border-radius:10px; padding:11px 12px; font:inherit; color:var(--text); }\n  input::placeholder { color:#5a5a6a; }\n  input:focus, select:focus { outline:none; border-color:var(--accent); }\n  .hint { font-size:12px; color:var(--muted); margin-top:4px; }\n  button { background:var(--accent); color:#fff; border:0; border-radius:11px; padding:12px 20px; font:inherit; font-weight:700; cursor:pointer; margin-top:20px; transition:.15s; }\n  button:hover { background:#8b5cf6; }\n  button:disabled { opacity:.55; cursor:default; }\n  .ghost { background:transparent; border:1px solid var(--line); color:var(--text); }\n  .err { color:var(--err); font-size:13.5px; margin-top:12px; min-height:1em; }\n  .keybox, .snip { margin-top:16px; background:#0d0d13; border:1px solid var(--line); border-radius:11px; padding:14px; font-family:ui-monospace,\"SF Mono\",Menlo,monospace; font-size:13px; word-break:break-all; position:relative; }\n  .keybox { border-color:rgba(124,58,237,.4); }\n  .copy { position:absolute; top:8px; right:8px; padding:5px 10px; font-size:12px; margin:0; }\n  .warn { font-size:12.5px; color:var(--accent2); margin-top:8px; }\n  .hidden { display:none; }\n  .foot { margin-top:18px; font-size:13px; color:var(--muted); }\n  .foot a { color:var(--accent2); text-decoration:none; }\n  #preview { margin-top:18px; height:420px; border:1px solid var(--line); border-radius:14px; overflow:hidden; }\n</style>\n</head>\n<body>\n<div class=\"wrap\">\n  <div class=\"brand\">\n    <svg viewBox=\"0 0 100 100\" aria-hidden=\"true\"><rect x=\"8\" y=\"8\" width=\"84\" height=\"84\" rx=\"24\" fill=\"#7C3AED\"/><circle cx=\"50\" cy=\"34\" r=\"10\" fill=\"#0B0B12\"/><path d=\"M27 64 L73 53\" stroke=\"#0B0B12\" stroke-width=\"11\" stroke-linecap=\"round\" fill=\"none\"/><path d=\"M27 53 L73 64\" stroke=\"#0B0B12\" stroke-width=\"11\" stroke-linecap=\"round\" fill=\"none\"/></svg>\n    <b>Bouncr</b>\n  </div>\n\n  <div class=\"steps\">\n    <div class=\"s on\" id=\"step-1\">1 · Account</div>\n    <div class=\"s\" id=\"step-2\">2 · Your plan</div>\n    <div class=\"s\" id=\"step-3\">3 · Embed</div>\n  </div>\n\n  <!-- Step 1: account -->\n  <section id=\"sec-1\">\n    <h1>Create your account</h1>\n    <p class=\"sub\">Stand up a bouncer for your product in two minutes.</p>\n    <div class=\"card\">\n      <form id=\"signup-form\" autocomplete=\"on\">\n        <label for=\"name\">Business / product name</label>\n        <input id=\"name\" placeholder=\"Obius\" required />\n        <label for=\"email\">Email <span style=\"opacity:.6\">(optional)</span></label>\n        <input id=\"email\" type=\"email\" placeholder=\"you@company.com\" autocomplete=\"email\" />\n        <div class=\"err\" id=\"signup-err\"></div>\n        <button id=\"signup-btn\" type=\"submit\">Create account →</button>\n      </form>\n    </div>\n    <p class=\"foot\">Already have a key? <a href=\"/dashboard\">Go to the dashboard</a>.</p>\n  </section>\n\n  <!-- Step 1b: show key -->\n  <section id=\"sec-key\" class=\"hidden\">\n    <h1>Save your API key</h1>\n    <p class=\"sub\">This is your dashboard login. We only store a hash — you won't see it again.</p>\n    <div class=\"card\">\n      <div class=\"keybox\" id=\"key-box\"><button class=\"copy ghost\" data-copy=\"key-box\">Copy</button><span id=\"key-val\"></span></div>\n      <div class=\"warn\">⚠ Store this somewhere safe (a password manager). It's shown once.</div>\n      <button id=\"key-continue\">I saved it — continue →</button>\n    </div>\n  </section>\n\n  <!-- Step 2: first plan -->\n  <section id=\"sec-2\" class=\"hidden\">\n    <h1>Set up your first plan</h1>\n    <p class=\"sub\">A few essentials — the rest gets sensible defaults you can tune later.</p>\n    <div class=\"card\">\n      <form id=\"plan-form\">\n        <label for=\"product\">Product name (what the bouncer is selling)</label>\n        <input id=\"product\" placeholder=\"Obius Pro\" required />\n        <div class=\"row\">\n          <div>\n            <label for=\"list\">List price ($/mo)</label>\n            <input id=\"list\" type=\"number\" min=\"1\" step=\"0.01\" placeholder=\"30\" required />\n          </div>\n          <div>\n            <label for=\"floor\">Floor — your cost ($/mo)</label>\n            <input id=\"floor\" type=\"number\" min=\"1\" step=\"0.01\" placeholder=\"22\" required />\n          </div>\n          <div>\n            <label for=\"target\">Target <span style=\"opacity:.6\">(optional)</span></label>\n            <input id=\"target\" type=\"number\" min=\"1\" step=\"0.01\" placeholder=\"= list\" />\n          </div>\n        </div>\n        <div class=\"hint\">The bouncer opens above list, aims at target, and will never close below your floor.</div>\n        <div class=\"row\">\n          <div>\n            <label for=\"persona\">Bouncer name</label>\n            <input id=\"persona\" placeholder=\"Vinny\" />\n          </div>\n          <div>\n            <label for=\"style\">Personality</label>\n            <select id=\"style\">\n              <option value=\"sassy\">Sassy</option>\n              <option value=\"playful\">Playful</option>\n              <option value=\"deadpan\">Deadpan</option>\n              <option value=\"professional\">Professional</option>\n            </select>\n          </div>\n        </div>\n        <div class=\"err\" id=\"plan-err\"></div>\n        <button id=\"plan-btn\" type=\"submit\">Create plan →</button>\n      </form>\n    </div>\n  </section>\n\n  <!-- Step 3: embed -->\n  <section id=\"sec-3\" class=\"hidden\">\n    <h1>Drop it on your pricing page</h1>\n    <p class=\"sub\">One tag mounts your bouncer wherever this element is.</p>\n    <div class=\"card\">\n      <div class=\"snip\" id=\"snip-box\"><button class=\"copy ghost\" data-copy=\"snip-box\">Copy</button><span id=\"snip-val\"></span></div>\n      <p class=\"hint\" style=\"margin-top:12px\">Add a target element too: <code>&lt;div id=\"bouncr\"&gt;&lt;/div&gt;</code></p>\n      <div id=\"preview\"></div>\n      <button id=\"to-dashboard\">Open your dashboard →</button>\n    </div>\n  </section>\n</div>\n\n<script src=\"/embed.js\"></script>\n<script>\n(() => {\n  const $ = (id) => document.getElementById(id);\n  const TKEY = \"bouncr_dash_token\";\n  const base = location.origin;\n  let token = null, newPlanId = null;\n\n  function show(sec) {\n    [\"sec-1\",\"sec-key\",\"sec-2\",\"sec-3\"].forEach((s) => $(s).classList.add(\"hidden\"));\n    $(sec).classList.remove(\"hidden\");\n  }\n  function mark(stepNum) {\n    [1,2,3].forEach((n) => {\n      const el = $(\"step-\" + n);\n      el.className = \"s\" + (n < stepNum ? \" done\" : n === stepNum ? \" on\" : \"\");\n    });\n  }\n  function copyText(id) {\n    const t = $(id.replace(\"-box\",\"-val\")).textContent;\n    navigator.clipboard && navigator.clipboard.writeText(t);\n  }\n  document.querySelectorAll(\".copy\").forEach((b) => b.onclick = (e) => { e.preventDefault(); copyText(b.dataset.copy); b.textContent = \"Copied\"; setTimeout(() => b.textContent = \"Copy\", 1200); });\n\n  // Step 1 — signup\n  $(\"signup-form\").addEventListener(\"submit\", async (e) => {\n    e.preventDefault();\n    $(\"signup-err\").textContent = \"\";\n    $(\"signup-btn\").disabled = true;\n    try {\n      const r = await fetch(base + \"/v1/signup\", {\n        method: \"POST\", headers: { \"content-type\": \"application/json\" },\n        body: JSON.stringify({ name: $(\"name\").value.trim(), email: $(\"email\").value.trim() || null }),\n      });\n      const d = await r.json();\n      if (!r.ok) throw new Error(d.error || \"signup failed\");\n      token = d.token; localStorage.setItem(TKEY, token);\n      $(\"key-val\").textContent = d.key;\n      mark(1); show(\"sec-key\");\n    } catch (err) { $(\"signup-err\").textContent = err.message; }\n    finally { $(\"signup-btn\").disabled = false; }\n  });\n  $(\"key-continue\").onclick = () => { mark(2); show(\"sec-2\"); };\n\n  // Step 2 — create plan\n  $(\"plan-form\").addEventListener(\"submit\", async (e) => {\n    e.preventDefault();\n    $(\"plan-err\").textContent = \"\";\n    $(\"plan-btn\").disabled = true;\n    try {\n      const numv = (id) => { const v = parseFloat($(id).value); return Number.isFinite(v) ? v : null; };\n      const body = {\n        product_name: $(\"product\").value.trim(),\n        list_price: numv(\"list\"),\n        floor_price: numv(\"floor\"),\n        persona_name: $(\"persona\").value.trim() || undefined,\n        persona_style: $(\"style\").value,\n      };\n      const tv = numv(\"target\"); if (tv !== null) body.target_price = tv;\n      const r = await fetch(base + \"/v1/plans\", {\n        method: \"POST\", headers: { \"content-type\": \"application/json\", authorization: \"Bearer \" + token },\n        body: JSON.stringify(body),\n      });\n      const d = await r.json();\n      if (!r.ok) throw new Error(d.error || \"could not create plan\");\n      newPlanId = d.plan.id;\n      $(\"snip-val\").textContent = d.embed.snippet;\n      mark(3); show(\"sec-3\");\n      try { window.Bouncr && Bouncr.mount({ el: \"#preview\", planId: newPlanId, userRef: \"preview_\" + Math.random().toString(36).slice(2,8) }); } catch (_) {}\n    } catch (err) { $(\"plan-err\").textContent = err.message; }\n    finally { $(\"plan-btn\").disabled = false; }\n  });\n\n  $(\"to-dashboard\").onclick = () => { location.href = \"/dashboard\"; };\n})();\n</script>\n</body>\n</html>\n";
